import React from 'react';

function AboutMe() {
  return (
    <div style={{ padding: '2rem' }}>
      <h1>About Me</h1>
      <p>
        Welcome to Dora's Clothing Store! I'm Dora, the founder of this fashion space.
        We bring you stylish, quality clothing at affordable prices. 💃🕺
      </p>
      <p>Thank you for visiting our store!</p>
    </div>
  );
}

export default AboutMe;
